previewCss:
.darma-loader-darma-custom-155 {
  color: var(--loader-color, #ca8a04);
width: 45px;
height: 30px;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color, #facc15));
background:
var(--c) 0 100%/8px 30px,
var(--c) 50% 100%/8px 20px,
var(--c) 100% 100%/8px 10px;
position: relative;
clip-path: inset(-100% 0);
}
.darma-loader-darma-custom-155:before{
content: "";
position: absolute;
width: 8px;
height: 8px;
border-radius: 50%;
background: currentColor;
left: -16px;
top: 0;
animation:
darma-loader-darma-custom-155-l5-1 2s linear infinite,
darma-loader-darma-custom-155-l5-2 0.5s cubic-bezier(0,200,.8,200) infinite;
}
@keyframes darma-loader-darma-custom-155-l5-1 {
0% {left:-16px;transform:translateY(-8px)}
100% {left:calc(100% + 8px);transform:translateY(22px)}
}
@keyframes darma-loader-darma-custom-155-l5-2 {
100% {top:-0.1px}
}

